# Geometric shapes module with abstract base classes and interfaces

interface IDrawable:
    def draw(self) -> str: ...

interface IMeasurable:
    @property get area(self) -> float: ...

@abstract
class Shape:
    name: str

    def __init__(self, name: str):
        self.name = name

    @virtual
    def describe(self) -> str:
        return "Shape: " + self.name

    @abstract
    def calculate_area(self) -> float: ...

@abstract
class Polygon(Shape):
    sides: int

    def __init__(self, name: str, sides: int):
        super().__init__(name)
        self.sides = sides

    @override
    def describe(self) -> str:
        base = super().describe()
        return base + " with " + str(self.sides) + " sides"

    @virtual
    def get_perimeter(self) -> float:
        return 0.0

class Rectangle(Polygon):
    width: float
    height: float

    def __init__(self, width: float, height: float):
        super().__init__("Rectangle", 4)
        self.width = width
        self.height = height

    @override
    def calculate_area(self) -> float:
        return self.width * self.height

    @override
    def get_perimeter(self) -> float:
        return 2.0 * (self.width + self.height)

    def __str__(self) -> str:
        return "Rectangle(" + str(self.width) + "x" + str(self.height) + ")"

    def __eq__(self, other: object) -> bool:
        if other is Rectangle:
            r: Rectangle = other
            return self.width == r.width and self.height == r.height
        return False

class Circle(Shape):
    radius: float

    def __init__(self, radius: float):
        super().__init__("Circle")
        self.radius = radius

    @override
    def calculate_area(self) -> float:
        import math
        return math.pi * self.radius * self.radius

    def __str__(self) -> str:
        return "Circle(r=" + str(self.radius) + ")"

